(12009, 'zhTW', '在傳奇難度的三傑議會之座中，所有隊伍成員受到沉重黑暗效果影響後再擊敗路拉。', '黑暗面', '', 67186),
(12005, 'zhTW', '在傳奇難度的三傑議會之座中，讓暗牙使用暗影突襲破壞4個密封的虛無寶箱後擊敗賽普瑞許。', '開箱高手', '', 67186),
(12004, 'zhTW', '在傳奇難度的三傑議會之座中，使用虛無裂口將厄加德帶出虛無之域，再擊敗他跟『超凡者』祖拉爾。', '恭迎虛無', '', 67186),
(9036, 'zhTW', '在英雄難度中，於不殺死任何護盾傀儡的情況下擊敗擎天峰的大賢者維瑞思。', '偏執狂', '', 67186),
(9035, 'zhTW', '在英雄難度中，於擎天峰與盧克然的交鋒過程中同時使三個灰燼堆形成太陽閃焰。', '明心見性', '', 67186),
(9034, 'zhTW', '在英雄難度中，擊敗擎天峰的強化傀儡。', '放大…強化', '', 67186),
(9033, 'zhTW', '在英雄難度中，擊敗擎天峰的蘭吉特而不受到以下任何技能的傷害：旋轉利刃、風牆、四方之風、眩光。', '準備好出副本之四', '', 67186),
(4525, 'zhTW', '英雄難度中，在第一次交戰數且沒有人受到冰柱傷害的情況下，剷除所有在薩倫之淵中天譴領主提朗紐斯前走廊內的所有敵人。', '別往上看', '', 67186),
(4524, 'zhTW', '英雄難度中，在極寒冰霜累積到11層前，擊敗薩倫之淵的鍛造大師加弗羅斯。', '別到十一', '', 67186),
(62814, 'zhTW', '', '', '', 67186),
(62813, 'zhTW', '', '', '', 67186),
(62812, 'zhTW', '', '', '', 67186),
(62811, 'zhTW', '', '', '', 67186),
(62296, 'zhTW', '', '獲得神話晨曦紋章', '', 67186),
(42769, 'zhTW', '在至暗之夜第1賽季達到不再適用英雄晨曦紋章的程度。', '黎明英雄', '角色解鎖：以英雄晨曦紋章交換神話晨曦紋章', 67186);
INSERT INTO `battle_pet_species_locale` (`ID`, `locale`, `Description_lang`, `SourceText_lang`, `VerifiedBuild`) VALUES
(5065, 'zhTW', '真正的深淵釣手，由深海潛水者捷朱親自認證。', '|cFFFFD200商人：|r深海潛水者圖納基特|n|cFFFFD200區域：|r祖阿曼|n|cFFFFD200花費：|r2400|Hcurrency:3373|h|TInterface\\ICONS\\Item_enchantedpearl.blp:0|t|h|n|n', 67186);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(309753, 'zhTW', '你想要測量哪一項數據？', '你想要測量哪一項數據？', 67186),
(295258, 'zhTW', '', '做好準備。看來剛才的不過是些小卒子。', 67186),
(289969, 'zhTW', '我有太多的族人死在白銀誓盟手中。\n\n他們告訴我，那是戰爭。他們說，雙方都損失慘重。我們奪日者一族從未殺害達拉然的任何一個人。\n\n一個風行者已經因屠城而遭到報應。今天輪到另一個了。', '', 67186),
(294283, 'zhTW', '我是莉莉的哥哥，希賽。真希望你來的那天我能去歡迎你。現在大家都在等我們嗎？\n\n我前幾天在武松村裡為節慶做準備，結果發現最特別的煙火不見了！我回到家裡去找，但卻一無所獲。我們時間不多。只能臨機應變了。\n\n<希賽用爪子拂過眉梢。>\n\n很高興見到你，莉莉的朋友。我有好幾年沒見過她了，我也知道我們還有很多冒險故事可以聊。當然，主要是聽她說啦。之後我就搬家到晨風村。就在湖旁邊而已，那裡的景色很優美。', '', 67186);
