INSERT INTO `currency_types_locale` (`ID`, `locale`, `Name_lang`, `Description_lang`, `VerifiedBuild`) VALUES
(3513, 'zhTW', '星雲虛無之核', '在至暗之夜第1賽季團隊副本中擊敗強大的敵人，或完成傳奇鑰石地城、豐碩探究和夢魘難度的狩獵時，可轉化為強力的裝備。', 67186),
(3347, 'zhTW', '神話晨曦紋章', '用來升級至暗之夜第1季的傳奇裝備，最高可到物品等級276-289。\n\n製作時使用，會取決品級將物品等級定為272-285。\n\n透過下列活動獲取：\n\n- 虛無之尖、夢境裂隙、進軍奎爾達納斯傳奇難度\n- 傳奇鑰石難度地城（+9以上）', 67186),
(3346, 'zhTW', '英雄晨曦紋章', '用來升級至暗之夜第1季的英雄裝備，最高可到物品等級263-276。透過下列活動獲取：\n\n- 虛無之尖、夢境裂隙、進軍奎爾達納斯英雄難度\n- 傳奇鑰石難度地城（+4至+8）\n- 探究（級別11）\n- 寶箱獵人的獎賞（級別8以上）\n- 狩獵（夢魘）', 67186),
(3345, 'zhTW', '英雄晨曦紋章', '用來升級至暗之夜第1季的英雄裝備，最高可到物品等級263-276。\n\n製作時使用，會取決品級將物品等級定為259-272。\n\n透過下列活動獲取：\n\n- 虛無之尖、夢境裂隙、進軍奎爾達納斯英雄難度\n- 傳奇鑰石難度地城（+4至+8）\n- 探究（級別11）\n- 寶箱獵人的獎賞（級別8以上）\n- 狩獵（夢魘）', 67186),
(3344, 'zhTW', '勇士晨曦紋章', '用來升級至暗之夜第1季的勇士裝備，最高可到物品等級250-263。透過下列活動獲取：\n\n- 每週戶外活動\n- 虛無之尖、夢境裂隙、進軍奎爾達納斯普通難度\n- 傳奇難度賽季地城\n- 傳奇鑰石難度地城（+2至+3）\n- 探究（級別7至10）\n- 寶箱獵人的獎賞（級別6至7）\n- 狩獵（夢魘）', 67186),
(3343, 'zhTW', '勇士晨曦紋章', '用來升級至暗之夜第1季的勇士裝備，最高可到物品等級250-263。透過下列活動獲取：\n\n- 每週戶外活動\n- 虛無之尖、夢境裂隙、進軍奎爾達納斯普通難度\n- 傳奇難度賽季地城\n- 傳奇鑰石難度地城（+2至+3）\n- 探究（級別7至10）\n- 寶箱獵人的獎賞（級別6至7）\n- 狩獵（夢魘）', 67186),
(3342, 'zhTW', '精兵晨曦紋章', '用來升級至暗之夜第1季的精兵裝備，最高可到物品等級237-250。透過下列活動獲取：\n\n- 重複進行的戶外活動\n- 虛無之尖、夢境裂隙、進軍奎爾達納斯隨機團隊難度\n- 英雄難度賽季地城\n- 探究（級別5至6）\n- 寶箱獵人的獎賞（級別4至5）\n- 狩獵（困難）', 67186),
(3341, 'zhTW', '精兵晨曦紋章', '用來升級至暗之夜第1季的精兵裝備，最高可到物品等級237-250。\n\n製作時使用，會取決品級將物品等級定為233-246。\n\n透過下列活動獲取：\n\n- 重複進行的戶外活動\n- 虛無之尖、夢境裂隙、進軍奎爾達納斯隨機團隊難度\n- 英雄難度賽季地城\n- 探究（級別5至6）\n- 寶箱獵人的獎賞（級別4至5）\n- 狩獵（困難）', 67186),
