INSERT INTO `journal_encounter_section_locale` (`ID`, `locale`, `Title_lang`, `BodyText_lang`, `VerifiedBuild`) VALUES
(32672, 'zhTW', '坦克', '$bullet;囤積者會在|cFF2959D3|Hspell:1235072|h[精明手段]|h|r期間，從最近的資源堆收集物資。\n$bullet;腐臭的蘑菇會在接觸時施加|cFF2959D3|Hspell:1234846|h[毒性孢子]|h|r，防止其引爆為|cFF2959D3|Hspell:1245593|h[腐臭爆發]|h|r。\n$bullet;|cFF2959D3|Hspell:1234681|h[貪婪低吼]|h|r和|cFF2959D3|Hspell:1235125|h[豪邁低吼]|h|r對所有玩家造成大量傷害。', 67186),
(32669, 'zhTW', '概況說明', '囤積者不惜一切代價守護他的存貨，並在生命力降至90%、60%與30%時施放|cFF2959D3|Hspell:1235072|h[精明手段]|h|r，強化其中一個技能。\n\n當能量達到100點時，他會在場上到處亂丟|cFF2959D3|Hspell:1234233|h[腐敗的補給品]|h|r，使腐臭的蘑菇生長12秒。接觸到蘑菇時，會施加|cFF2959D3|Hspell:1234846|h[毒性孢子]|h|r並摧毀蕈菇，防止觸發|cFF2959D3|Hspell:1245593|h[腐臭爆發]|h|r。', 67186),
(31527, 'zhTW', '禁忌運輸', '一批原本用來避人耳目的貨物。可提供極佳的掩護。', 67186),
(31282, 'zhTW', '坦克', '$bullet;克絲提雅會使用|cFF2959D3|Hspell:1230289|h[禁忌灌注]|h|r使尼波斯變為玩家的敵對目標。\n$bullet;躲開尼波斯的|cFF2959D3|Hspell:1253811|h[魔化噴霧]|h|r。\n$bullet;中斷克絲提雅的|cFF2959D3|Hspell:1264095|h[鏡象]|h|r。', 67186),
(31281, 'zhTW', '治療者', '$bullet;克絲提雅會使用|cFF2959D3|Hspell:1230289|h[禁忌灌注]|h|r使尼波斯變為玩家的敵對目標。\n$bullet;躲開尼波斯的|cFF2959D3|Hspell:1253811|h[魔化噴霧]|h|r。\n$bullet;克絲提雅在|cFF2959D3|Hspell:1265412|h[異變]|h|r狀態下會對所有玩家造成大量傷害。', 67186),
(31280, 'zhTW', '傷害輸出', '$bullet;克絲提雅會使用|cFF2959D3|Hspell:1230289|h[禁忌灌注]|h|r使尼波斯變為玩家的敵對目標。\n$bullet;躲開尼波斯的|cFF2959D3|Hspell:1253811|h[魔化噴霧]|h|r。\n$bullet;中斷克絲提雅的|cFF2959D3|Hspell:1264095|h[鏡象]|h|r。', 67186),
(35862, 'zhTW', 'Section 18', '', 67186),
(35353, 'zhTW', '第17區', '|n\nBy speaking with Lindormi near The Timeways portal or at the end of a Keystone Dungeon, characters with a tank specialization can enable |cFF2959D3|Hspell:1295986|h[Lindormi\'s Glow]|h|r when |cFF2959D3|Hspell:1278156|h[Lindormi\'s Guidance]|h|r is inactive.', 67186),
(34751, 'zhTW', '第17區', '', 67186),
(34733, 'zhTW', '薩拉塔斯之詐', '薩拉塔斯會背叛玩家，撤回她的交易，並讓死亡扣除15秒剩餘時間。', 67186),
(34732, 'zhTW', '強悍', '非首領敵人生命力提高20%，造成的傷害提高20%。', 67186),
(34731, 'zhTW', '暴君', '首領的生命力提高25%。首領與其爪牙所造成的傷害提高15%。', 67186),
(34730, 'zhTW', '暴君和強悍', '這些詞綴會進一步強化傳奇鑰石地城中的敵人。其中一項會在傳奇等級7時啟動，其他則在傳奇等級10時啟動，並會每週輪替。', 67186),
(34727, 'zhTW', '薩拉塔斯的交易：吞噬', '', 67186),
(34725, 'zhTW', '薩拉塔斯的交易：虛無之縛', '', 67186),
(34722, 'zhTW', '薩拉塔斯的交易：星體', '', 67186),
(34720, 'zhTW', '傳奇等級6', '$bullet;移除|cFF2959D3|Hspell:1284818|h[林多米的指引]|h|r。\n\n使用坦克專精的角色可以在時間之道傳送門附近，或於鑰石地城結束時與林多米對話，以獲得|cFF2959D3|Hspell:1295986|h[林多米的光輝]|h|r，此效果將會繼續標出敵方部隊。', 67186),
(35809, 'zhTW', 'Section 158', '', 67186),
(35491, 'zhTW', '第69區', '', 67186),
(35490, 'zhTW', '第70區', '', 67186),
(35489, 'zhTW', '第76區', '', 67186),
