INSERT INTO `mail_template_locale` (`ID`, `locale`, `Body_lang`, `VerifiedBuild`) VALUES
(659, 'zhTW', '你好，侍僧！\n\n見證發生在這片地域的奇蹟，光榮豐足滿溢！豐足湧現、湧動，拒絕所有阻礙！\n\n你為我的犧牲奉獻，使你獲得小小的恩惠。這次，是以純粹豐足的形式！\n\n請注意，虔敬的侍僧：某些獻禮，例如融合活力，現在將會出現在其他供應商之間。只要你冒險經過祖阿曼深海附近，或許就會遇見他們。\n\n祝你收穫滿滿\n\n-『豐足羅亞』敦敦', 67186);
